// src/pages/admin/RoleManagementPage.js
import React, { useState, useEffect, useCallback } from 'react';
import { useToast } from '../../context/ToastContext';
import api from '../../services/api';
import './AdminPages.css';

const RoleManagementPage = () => {
    const { showSuccess, showError } = useToast();
    const [roles, setRoles] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showForm, setShowForm] = useState(false);
    const [editingRole, setEditingRole] = useState(null);
    const [formData, setFormData] = useState({
        name: '',
        description: '',
        permissions: []
    });
    const [permissionInput, setPermissionInput] = useState('');

    const availablePermissions = [
        // Patient permissions
        'view_own_records', 'create_own_records', 'update_own_records',
        'view_own_appointments', 'create_appointments', 'cancel_appointments',
        'view_own_prescriptions', 'request_refills', 'view_own_profile',
        'update_own_profile', 'change_own_password',
        
        // Clinical permissions
        'view_patient_records', 'create_patient_records', 'update_patient_records',
        'view_all_appointments', 'manage_appointments', 'view_patient_list',
        'create_prescriptions', 'update_prescriptions', 'view_all_prescriptions',
        'update_patient_vitals', 'assist_in_appointments',
        
        // Diagnostic permissions
        'view_lab_requests', 'update_lab_results', 'view_imaging_requests',
        'update_imaging_results', 'perform_lab_tests', 'record_test_results',
        'perform_imaging', 'interpret_images', 'write_imaging_reports',
        
        // Therapeutic permissions
        'view_therapy_requests', 'create_therapy_plans', 'update_therapy_plans',
        'schedule_therapy_sessions', 'record_therapy_notes', 'view_therapy_history',
        'create_diet_plans', 'update_diet_plans',
        
        // Pharmacy permissions
        'dispense_medication', 'update_prescription_status', 'manage_inventory',
        'view_patient_allergies',
        
        // Administrative permissions
        'register_patients', 'schedule_appointments', 'update_patient_demographics',
        'manage_payments', 'view_invoices', 'create_invoices', 'process_payments',
        'view_insurance_claims', 'submit_claims', 'view_financial_reports',
        
        // Management permissions
        'manage_staff', 'manage_users', 'manage_roles', 'view_audit_logs',
        'manage_system_settings', 'backup_database', 'restore_database',
        'view_all_data', 'manage_permissions', 'view_department_stats',
        'manage_department_schedules', 'approve_leave_requests', 'view_department_reports'
    ];

    const fetchRoles = useCallback(async () => {
        try {
            setLoading(true);
            const response = await api.get('/roles');
            setRoles(response.data);
        } catch (error) {
            showError('Failed to load roles');
        } finally {
            setLoading(false);
        }
    }, [showError]);

    useEffect(() => {
        fetchRoles();
    }, [fetchRoles]);

    const handleInputChange = (e) => {
        setFormData({
            ...formData,
            [e.target.name]: e.target.value
        });
    };

    const handleAddPermission = () => {
        if (permissionInput && !formData.permissions.includes(permissionInput)) {
            setFormData({
                ...formData,
                permissions: [...formData.permissions, permissionInput]
            });
            setPermissionInput('');
        }
    };

    const handleRemovePermission = (permission) => {
        setFormData({
            ...formData,
            permissions: formData.permissions.filter(p => p !== permission)
        });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        
        if (!formData.name) {
            showError('Role name is required');
            return;
        }
        
        try {
            if (editingRole) {
                await api.put(`/master-admin/roles/${editingRole.id}`, {
                    name: formData.name,
                    description: formData.description,
                    permissions: formData.permissions
                });
                showSuccess('Role updated successfully');
            } else {
                await api.post('/master-admin/roles', {
                    name: formData.name,
                    description: formData.description,
                    permissions: formData.permissions
                });
                showSuccess('Role created successfully');
            }
            setShowForm(false);
            setEditingRole(null);
            setFormData({ name: '', description: '', permissions: [] });
            setPermissionInput('');
            fetchRoles();
        } catch (error) {
            showError(error.response?.data?.error || 'Failed to save role');
        }
    };

    const handleEdit = (role) => {
        setEditingRole(role);
        setFormData({
            name: role.name,
            description: role.description || '',
            permissions: role.permissions || []
        });
        setPermissionInput('');
        setShowForm(true);
    };

    const handleDelete = async (roleId, roleName) => {
        if (roleName === 'master_admin') {
            showError('Cannot delete master_admin role');
            return;
        }
        
        if (window.confirm(`Are you sure you want to delete the "${roleName}" role? This action cannot be undone.`)) {
            try {
                await api.delete(`/master-admin/roles/${roleId}`);
                showSuccess('Role deleted successfully');
                fetchRoles();
            } catch (error) {
                showError(error.response?.data?.error || 'Failed to delete role');
            }
        }
    };

    const getPermissionsCount = (permissions) => {
        if (!permissions || permissions.length === 0) return 'No permissions';
        return `${permissions.length} permission${permissions.length !== 1 ? 's' : ''}`;
    };

    const getRoleIcon = (roleName) => {
        const icons = {
            'master_admin': '👑',
            'patient': '👤',
            'doctor': '👨‍⚕️',
            'nurse': '👩‍⚕️',
            'diagnostic_staff': '🔬',
            'lab_technician': '🧪',
            'radiologist': '📷',
            'therapeutic_staff': '💪',
            'physiotherapist': '🦵',
            'nutritionist': '🥗',
            'pharmacist': '💊',
            'receptionist': '📋',
            'billing_officer': '💰',
            'ict_admin': '💻',
            'hr_admin': '👥',
            'department_head': '👔'
        };
        return icons[roleName] || '📁';
    };

    if (loading) return <div className="loading">Loading roles...</div>;

    return (
        <div className="admin-page">
            <div className="page-header">
                <h1>Role Management</h1>
                <button 
                    className="btn-primary"
                    onClick={() => {
                        setEditingRole(null);
                        setFormData({ name: '', description: '', permissions: [] });
                        setPermissionInput('');
                        setShowForm(true);
                    }}
                >
                    + Add New Role
                </button>
            </div>

            {showForm && (
                <div className="role-form">
                    <h2>{editingRole ? 'Edit Role' : 'Create New Role'}</h2>
                    <form onSubmit={handleSubmit}>
                        <div className="form-group">
                            <label>Role Name *</label>
                            <input
                                type="text"
                                name="name"
                                value={formData.name}
                                onChange={handleInputChange}
                                required
                                placeholder="e.g., radiologist, lab_technician"
                                pattern="[a-z_]+"
                                title="Use lowercase letters and underscores only"
                            />
                            <small>Use lowercase letters and underscores (e.g., lab_technician)</small>
                        </div>
                        
                        <div className="form-group">
                            <label>Description</label>
                            <textarea
                                name="description"
                                value={formData.description}
                                onChange={handleInputChange}
                                rows="3"
                                placeholder="Describe the role and its responsibilities..."
                            />
                        </div>
                        
                        <div className="form-group">
                            <label>Permissions</label>
                            <div className="permission-input-group">
                                <select 
                                    value={permissionInput}
                                    onChange={(e) => setPermissionInput(e.target.value)}
                                    className="permission-select"
                                >
                                    <option value="">Select a permission...</option>
                                    {availablePermissions
                                        .filter(p => !formData.permissions.includes(p))
                                        .map(perm => (
                                            <option key={perm} value={perm}>
                                                {perm.replace(/_/g, ' ').toUpperCase()}
                                            </option>
                                        ))}
                                </select>
                                <button 
                                    type="button" 
                                    onClick={handleAddPermission}
                                    className="btn-small btn-primary"
                                    disabled={!permissionInput}
                                >
                                    Add
                                </button>
                            </div>
                            
                            {formData.permissions.length > 0 && (
                                <div className="permissions-list">
                                    <strong>Selected Permissions ({formData.permissions.length}):</strong>
                                    <div className="permissions-tags">
                                        {formData.permissions.map(perm => (
                                            <span key={perm} className="permission-tag">
                                                {perm.replace(/_/g, ' ').toUpperCase()}
                                                <button
                                                    type="button"
                                                    onClick={() => handleRemovePermission(perm)}
                                                    className="remove-permission"
                                                >
                                                    ×
                                                </button>
                                            </span>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                        
                        <div className="form-actions">
                            <button type="submit" className="btn-success">
                                {editingRole ? 'Update Role' : 'Create Role'}
                            </button>
                            <button 
                                type="button" 
                                className="btn-secondary"
                                onClick={() => {
                                    setShowForm(false);
                                    setEditingRole(null);
                                    setFormData({ name: '', description: '', permissions: [] });
                                    setPermissionInput('');
                                }}
                            >
                                Cancel
                            </button>
                        </div>
                    </form>
                </div>
            )}

            <div className="roles-list">
                <h2>System Roles ({roles.length})</h2>
                <div className="roles-grid">
                    {roles.map(role => (
                        <div key={role.id} className="role-card">
                            <div className="role-card-header">
                                <span className="role-icon">{getRoleIcon(role.name)}</span>
                                <div className="role-info">
                                    <h3>{role.name.replace(/_/g, ' ').toUpperCase()}</h3>
                                    <p className="role-description">{role.description || 'No description provided'}</p>
                                </div>
                                {role.name === 'master_admin' && (
                                    <span className="master-badge">System</span>
                                )}
                            </div>
                            <div className="role-stats">
                                <span className="permissions-count">
                                    📋 {getPermissionsCount(role.permissions)}
                                </span>
                            </div>
                            {role.permissions && role.permissions.length > 0 && (
                                <div className="role-permissions-preview">
                                    <strong>Sample permissions:</strong>
                                    <div className="permission-preview-tags">
                                        {role.permissions.slice(0, 3).map(perm => (
                                            <span key={perm} className="preview-tag">
                                                {perm.split('_').slice(0, 2).join(' ')}
                                            </span>
                                        ))}
                                        {role.permissions.length > 3 && (
                                            <span className="preview-tag more">
                                                +{role.permissions.length - 3}
                                            </span>
                                        )}
                                    </div>
                                </div>
                            )}
                            <div className="role-card-actions">
                                <button 
                                    className="btn-small btn-primary"
                                    onClick={() => handleEdit(role)}
                                    disabled={role.name === 'master_admin'}
                                >
                                    Edit
                                </button>
                                <button 
                                    className="btn-small btn-danger"
                                    onClick={() => handleDelete(role.id, role.name)}
                                    disabled={role.name === 'master_admin'}
                                >
                                    Delete
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
};

export default RoleManagementPage;
